    "loader_text": "Loading Security",
    "sec_badge": "Security-first architecture",
    "sec_h1_1": "Your privacy is",
    "sec_h1_2": "non-negotiable.",
    "sec_hero_desc": "ThePost.Space was built with security as a foundation, not an afterthought. End-to-end encryption, zero-knowledge architecture, and full regulatory compliance — so your data stays yours, always.",
    "sec_cta_primary": "Submit Application",
    "sec_cta_secondary": "Read the whitepaper",
    "pillars_label": "Security Pillars",
    "pillars_title": "Six layers of protection",
    "pillars_sub": "Every aspect of ThePost.Space is engineered around your security. From the code we write to the infrastructure we run.",
    "p1_t": "End-to-End Encryption",
    "p1_d": "Every message is encrypted on your device before transmission. We use AES-256 combined with RSA-4096 key exchange — the same standard trusted by governments and financial institutions.",
    "p1_detail": "AES-256 + RSA-4096",
    "p2_t": "Zero-Knowledge Design",
    "p2_d": "We never have access to your encryption keys. Your private key is generated on your device and never leaves it. Even our engineers cannot read your messages — this is a technical guarantee, not a policy.",
    "p2_detail": "Keys never leave your device",
    "p3_t": "Hardened Infrastructure",
    "p3_d": "Our servers run in ISO 27001-certified data centres with physical access controls, network segmentation, and 24/7 intrusion detection. All data is replicated across geographically separated regions.",
    "p3_detail": "ISO 27001-certified DCs",
    "p4_t": "Threat Protection",
    "p4_d": "Our AI-powered filters block spam, phishing links, and malware attachments with 99.7% accuracy — before they ever reach your inbox. Threat models are updated continuously in real time.",
    "p4_detail": "99.7% spam & phishing block rate",
    "p5_t": "Access Control",
    "p5_d": "Multi-factor authentication, hardware security key support (FIDO2/WebAuthn), session management, and granular team permission controls. You decide exactly who sees what.",
    "p5_detail": "FIDO2 / WebAuthn / MFA",
    "p6_t": "Audit Logs",
    "p6_d": "Every login, file access, and administrative action is recorded in tamper-proof audit logs. Exportable for compliance reviews, SIEM integration, and forensic investigations.",
    "p6_detail": "Tamper-proof, exportable logs",
    "deepdive_label": "How encryption works",
    "deepdive_title": "Your message, always private",
    "deepdive_desc": "From the moment you hit send, your message is encrypted on-device. Our servers only ever see ciphertext — mathematically impossible to read without the recipient's private key. Not even a court order changes that.",
    "ef1_t": "Message composed",
    "ef2_t": "AES-256 encryption",
    "ef3_t": "RSA-4096 key exchange",
    "ef4_t": "TLS 1.3 transit",
    "ef5_t": "Stored encrypted-at-rest",
    "dd1_t": "Perfect Forward Secrecy",
    "dd1_d": "New encryption keys generated for every session. Past messages stay secure even if keys are ever compromised.",
    "dd2_t": "Open Source Cryptography",
    "dd2_d": "We use battle-tested, open-source cryptographic primitives. No proprietary algorithms — our implementation is auditable by anyone.",
    "dd3_t": "Independent Audits",
    "dd3_d": "Our cryptographic implementation is independently audited annually by third-party security firms. Full reports are publicly available.",
    "ss1_num": "256-bit",
    "ss1_lbl": "AES Encryption Standard",
    "ss2_num": "99.7%",
    "ss2_lbl": "Spam & Phishing Block Rate",
    "ss3_num": "0",
    "ss3_lbl": "Data Breaches Since Launch",
    "ss4_num": "24/7",
    "ss4_lbl": "Security Operations Centre",
    "cert1_t": "SOC 2 Type II",
    "cert1_d": "Independently audited by a Big Four firm. Covers security, availability, processing integrity, confidentiality, and privacy of customer data. Re-audited annually.",
    "cert2_t": "GDPR Compliance",
    "cert2_d": "Full compliance with the EU General Data Protection Regulation. Data processing agreements available. EU users' data stays within the EU by default.",
    "cert3_t": "CCPA Compliance",
    "cert3_d": "Full compliance with the California Consumer Privacy Act. California residents have the right to access, delete, and opt out of the sale of their personal information.",
    "cert4_t": "ISO 27001",
    "cert4_d": "Our information security management system is certified to ISO/IEC 27001:2022 — the international gold standard for information security.",
    "cert_certified": "Certified",
    "cert_compliant": "Compliant",
    "threat_label": "Active Protection",
    "threat_title": "Threats stopped before they reach you",
    "threat_desc": "Our multi-layered threat intelligence system analyses billions of data points daily. Every suspicious pattern is blocked in real time — with zero false positive impact on legitimate mail.",
    "th1_t": "Phishing & Spoofing Detection",
    "th1_d": "AI-powered analysis of sender reputation, domain age, link patterns, and content to catch even the most sophisticated phishing attempts.",
    "th2_t": "Malware & Attachment Scanning",
    "th2_d": "Every attachment is scanned in a sandboxed environment using multiple antivirus engines before delivery. Macros and executables are blocked by default.",
    "th3_t": "DDoS & Abuse Prevention",
    "th3_d": "Rate limiting, geo-based anomaly detection, and automatic DDoS mitigation ensure your service stays online even under heavy attack conditions.",
    "faq_sub": "Transparency is part of our security model. Here are the questions we get asked most.",
